using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");
var errors = build.FindChildrenRecursive<Error>();
var warnings = build.FindChildrenRecursive<Warning>();

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

foreach (var error in errors)
{
    var project = error.GetNearestParent<Project>();
    var projectName = project?.Name ?? "Unknown";
    Console.WriteLine($"Project: {projectName}");
    Console.WriteLine($"  Code: {error.Code}");
    Console.WriteLine($"  File: {error.File}");
    Console.WriteLine($"  Line: {error.LineNumber}");
    Console.WriteLine($"  Message: {error.Text}");
    Console.WriteLine();
}

Console.WriteLine("=== KEY WARNINGS (may indicate root causes) ===");
var importantWarnings = warnings.Where(w => 
    w.Code == "MSB3644" || w.Code == "MSB3270" || w.Code == "NU1605" || 
    w.Code == "CS8785" || w.Code?.StartsWith("NU") == true).Take(20).ToList();
Console.WriteLine($"Total warnings: {warnings.Count}, showing {importantWarnings.Count} important ones");
foreach (var w in importantWarnings)
{
    var project = w.GetNearestParent<Project>();
    Console.WriteLine($"  [{w.Code}] {project?.Name}: {w.Text}");
}
EOF
