#r "nuget: MSBuild.StructuredLogger, 2.2.405"

using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");

// Look for package references in the project
var items = build.FindChildrenRecursive<AddItem>().Where(a => a.Name == "PackageReference" || a.Name == "Reference");
Console.WriteLine("=== PACKAGE REFERENCES ===");
foreach (var item in items)
{
    var project = item.GetNearestParent<Project>();
    Console.WriteLine($"  {project?.Name} -> {item.Name}: {string.Join(", ", item.Children.Select(c => c.ToString()))}");
}

// Look for restore-related messages
Console.WriteLine("\n=== RESTORE MESSAGES ===");
var messages = build.FindChildrenRecursive<Message>().Where(m => 
    m.Text?.Contains("Newtonsoft") == true || m.Text?.Contains("restore") == true || m.Text?.Contains("PackageReference") == true).Take(20);
foreach (var m in messages)
{
    Console.WriteLine($"  {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
}

// Check all projects in the build
Console.WriteLine("\n=== ALL PROJECTS ===");
var projects = build.FindChildrenRecursive<Project>();
foreach (var p in projects)
{
    Console.WriteLine($"  {p.Name} (SourceFilePath: {p.SourceFilePath})");
}
EOF
